mapper.select:
SELECT ds.*, e.realname as physician_name, d.dept_name as department_name
FROM doctor_schedule ds
LEFT JOIN employee e ON ds.physician_id = e.id
LEFT JOIN department d ON ds.department_id = d.id
WHERE ds.physician_id = #{physicianId}
  AND ds.work_date = #{date}
  AND ds.time_slot = #{timeSlot}
  AND ds.delmark = 0

mapper.update:
UPDATE doctor_schedule
physician_id = #{physicianId}, work_date = #{workDate}, time_slot = #{timeSlot}, total_quota = #{totalQuota}, available_quota = #{availableQuota}, price = #{price}, status = #{status}, ai_suggestion = #{aiSuggestion}, modified = #{modified}, modify_remark = #{modifyRemark}, update_time = CURRENT_TIMESTAMP
WHERE id = #{id}

UPDATE register
SET employee_id = #{newPhysicianId}
WHERE scheduling_id = #{scheduleId}
  AND employee_id = #{oldPhysicianId}
